def parse_key_value_pairs(values: Optional[List[str]]) -> Dict[str, str]:
    result = {}
    if not values:
        return result
    for item in values:
        if "=" not in item:
            raise ValueError(f"Invalid key=value pair: {item}")
        key, value = item.split("=", 1)
        key = key.strip()
        if not key:
            raise ValueError(f"Invalid empty key in pair: {item}")
        result[key] = value
    return result


def parse_topics(topic_args: List[str], default_partitions: int, default_replication_factor: int, configs: Dict[str, str]) -> List[NewTopic]:
    topics = []
    for topic_name in topic_args:
        topics.append(
            NewTopic(
                name=topic_name,
                num_partitions=default_partitions,
                replication_factor=default_replication_factor,
                topic_configs=configs if configs else None,
            )
        )
    return topics


def get_admin_client(args) -> KafkaAdminClient:
    kwargs = {
        "bootstrap_servers": args.bootstrap_servers,
        "client_id": args.client_id,
    }
    if args.security_protocol:
        kwargs["security_protocol"] = args.security_protocol
    if args.sasl_mechanism:
        kwargs["sasl_mechanism"] = args.sasl_mechanism
    if args.sasl_plain_username is not None:
        kwargs["sasl_plain_username"] = args.sasl_plain_username
    if args.sasl_plain_password is not None:
        kwargs["sasl_plain_password"] = args.sasl_plain_password
    if args.ssl_cafile is not None:
        kwargs["ssl_cafile"] = args.ssl_cafile
    if args.ssl_certfile is not None:
        kwargs["ssl_certfile"] = args.ssl_certfile
    if args.ssl_keyfile is not None:
        kwargs["ssl_keyfile"] = args.ssl_keyfile
    return KafkaAdminClient(**kwargs)


def create_topics(admin: KafkaAdminClient, args) -> int:
    topic_configs = parse_key_value_pairs(args.topic_config)
    topics = parse_topics(args.topics, args.partitions, args.replication_factor, topic_configs)
    if not topics:
        print("No topics provided", file=sys.stderr)
        return 1
    try:
        futures = admin.create_topics(new_topics=topics, validate_only=args.validate_only)
        for topic, future in futures.items():
            try:
                future.result()
                print(f"Created topic: {topic}")
            except TopicAlreadyExistsError:
                print(f"Topic already exists: {topic}")
            except KafkaError as e:
                print(f"Failed to create topic {topic}: {e}", file=sys.stderr)
                return 1
        return 0
    except KafkaError as e:
        print(f"Error creating topics: {e}", file=sys.stderr)
        return 1


def alter_topic_config(admin: KafkaAdminClient, args) -> int:
    configs = parse_key_value_pairs(args.config)
    if not args.topics:
        print("No topics provided", file=sys.stderr)
        return 1
    if not configs:
        print("No config entries provided", file=sys.stderr)
        return 1

    resources = []
    for topic_name in args.topics:
        resources.append(
            ConfigResource(
                ConfigResourceType.TOPIC,
                topic_name,
                configs=configs,
            )
        )

    try:
        futures = admin.alter_configs(resources)
        for resource, future in futures.items():
            try:
                future.result()
                print(f"Updated config for topic: {resource.name}")
            except UnknownTopicOrPartitionError:
                print(f"Unknown topic: {resource.name}", file=sys.stderr)
                return 1
            except KafkaError as e:
                print(f"Failed to update config for topic {resource.name}: {e}", file=sys.stderr)
                return 1
        return 0
    except KafkaError as e:
        print(f"Error updating topic configs: {e}", file=sys.stderr)
        return 1


def describe_topic(admin: KafkaAdminClient, args) -> int:
    try:
        metadata = admin.describe_topics(args.topics)
        print(json.dumps(metadata, default=str, indent=2))
        return 0
    except KafkaError as e:
        print(f"Error describing topics: {e}", file=sys.stderr)
        return 1


def create_partitions(admin: KafkaAdminClient, args) -> int:
    if not args.topics:
        print("No topics provided", file=sys.stderr)
        return 1
    try:
        partitions_map = {topic: args.partitions for topic in args.topics}
        futures = admin.create_partitions(partitions_map)
        for topic, future in futures.items():
            try:
                future.result()
                print(f"Updated partitions for topic: {topic}")
            except UnknownTopicOrPartitionError:
                print(f"Unknown topic: {topic}", file=sys.stderr)
                return 1
            except KafkaError as e:
                print(f"Failed to update partitions for topic {topic}: {e}", file=sys.stderr)
                return 1
        return 0
    except KafkaError as e:
        print(f"Error creating partitions: {e}", file=sys.stderr)
        return 1


